--[[
Position = {Enabled = true, PosX   = (-) Move o item para Direita					(+) Move para Esquerda
PosY   = (-) Move o item para baixo						(+) Move o item para cima
AngleX = (-) Gira para esquerda ou direita				(+) 
AngleY = (-) Move o item em si para Esquerda 			(+) Move o item em sí para Direita	
AngleZ = (-) Gira para o Lado Direito 					(+) Gira para o Lado Esquerdo
--]]

function StartLoadItemPosition()
	if not CUSTOM_ITEM_POSITION_ENABLED then
		return
	end

	for i = 1, #CUSTOM_ITEM_POSITION do
		if CUSTOM_ITEM_POSITION[i].Position.Enabled then
			SetItemPosition(CUSTOM_ITEM_POSITION[i].ItemIndex, CUSTOM_ITEM_POSITION[i].Position.PosX, CUSTOM_ITEM_POSITION[i].Position.PosY, CUSTOM_ITEM_POSITION[i].Position.AngleX, CUSTOM_ITEM_POSITION[i].Position.AngleY, CUSTOM_ITEM_POSITION[i].Position.AngleZ)
		end

		if CUSTOM_ITEM_POSITION[i].Size.Enabled then
			SetItemSize(CUSTOM_ITEM_POSITION[i].ItemIndex, CUSTOM_ITEM_POSITION[i].Size.Scale)
		end
	end
end